function rightShiftOr(N, k, src, dest) {
    const rem = N % 32;
    const limit = (N >> 5) + 1;
    const n = (k >> 5);
    const b = k % 32;

    if (b) {
        dest[n] |= src[0] >>> b;
        for (let i = 1; i + n < limit; i++) {
            dest[n + i] |= (src[i - 1] << (32 - b)) | (src[i] >>> b);
        }
    } else {
        for (let i = 0; i + n < limit; i++) {
            dest[n + i] |= src[i];
        }
    }

    if (rem) {
        const mask = (1 << (32 - rem)) - 1;
        dest[limit - 1] &= ~mask;
    }
}

function leftShiftOr(N, k, src, dest) {
    const rem = N % 32;
    const limit = (N >> 5) + 1;
    const n = (k >> 5);
    const b = k % 32;

    if (b) {
        for (let i = 0; i + n + 1 < limit; i++) {
            dest[i] |= (src[n + i] << b) | (src[n + i + 1] >>> (32 - b));
        }
        dest[limit - n - 1] |= src[limit - 1] << b;
    } else {
        for (let i = 0; i + n < limit; i++) {
            dest[i] |= src[n + i];
        }
    }

    if (rem) {
        const mask = (1 << (32 - rem)) - 1;
        dest[limit - 1] &= ~mask;
    }
}

function EGZ_prime(p, arr) {
    if (p === 1) return new Array(1).fill(true);

    const ret = new Array(2 * p - 1).fill(false);
    const idx = Array.from({ length: 2 * p - 1 }, (_, i) => i);

    idx.sort((a, b) => arr[a] - arr[b]);

    // Cauchy-Davenport
    for (let i = 0; i < p; i++) {
        if (arr[idx[i]] === arr[idx[i + p - 1]]) {
            const limit = i + p;
            for (let j = i; j < limit; j++) ret[idx[j]] = true;
            return ret;
        }
    }

    let imod = arr.slice(0, p).reduce((acc, val) => acc + val, 0) % p;

    if (imod === 0) {
        for (let i = 0; i < p; i++) ret[idx[i]] = true;
        return ret;
    }

    const dp = new Array(p).fill(0);
    dp[imod] = 1;
    // 이분 탐색
    for (let i = 1; i < p; i++) {
        const diff = arr[idx[i + p - 1]] - arr[idx[i]];
        let next_mod = (imod + diff) % p;
        if (dp[next_mod]) {
            dp[next_mod] = dp[next_mod] || dp[imod];
        }
        imod = next_mod;
    }

    for (let i = 0; i < p; i++) {
        ret[idx[i]] = dp[i] ? true : false;
    }

    return ret;
}

function EGZ_composite(a, b, arr) {
    const index = [];
    let index_vector = [];
    let tp = 0;
    for (let j = 0; j < a - 1; j++) index_vector.push(tp++);
    for (let i = 0; i < 2 * b - 1; i++) {
        for (let j = 0; j < a; j++) index_vector.push(tp++);
        const recur_vector = index_vector.slice(0, 2 * a - 1).map(i => arr[i]);
        const recur_answer = EGZ(a, recur_vector);

        const push_index = [];
        const remain_index = [];
        for (let i = 0; i < 2 * a - 1; i++) {
            if (recur_answer[i]) push_index.push(index_vector[i]);
            else remain_index.push(index_vector[i]);
        }
        index_vector = remain_index;
        index.push(push_index);
    }

    const sum_vector = Array(2 * b - 1).fill(0);
    for (let i = 0; i < 2 * b - 1; i++) {
        let sum = 0;
        for (let j = 0; j < a; j++) sum += arr[index[i][j]];
        sum_vector[i] = (sum / a) % b;
    }

    const rec = EGZ(b, sum_vector);
    const ret = Array(2 * a * b - 1).fill(false);
    for (let i = 0; i < 2 * b - 1; i++) {
        if (rec[i]) {
            for (const j of index[i]) ret[j] = true;
        }
    }
    return ret;
}

function EGZ(N, arr) {
    if (isprime[N - 1]) return EGZ_composite(isprime[N - 1], N / isprime[N - 1], arr);
    return EGZ_prime(N, arr.map(x => x % N));
}

const lines = require('fs').readFileSync(0, 'utf-8').split('\n');
const N = parseInt(lines[0], 10);
let arr = lines[1].split(' ').map(Number).reverse();

const ans = EGZ(N, arr);
console.log(ans.map((val, i) => (val ? arr[i] : null)).filter(val => typeof val === 'number').join(' '));